USE driving_exam;

DELETE FROM question;

INSERT INTO question (category_id, type, content, options, answer, analysis, difficulty, chapter) VALUES
(1, 'single', '驾驶机动车在道路上违反道路交通安全法的行为，属于什么行为？', '{"A":"违章行为","B":"违法行为","C":"过失行为","D":"违规行为"}', 'B', '根据《道路交通安全法》，违反道路交通安全法律、法规的行为属于违法行为。', 2, '道路交通安全法律法规'),
(1, 'single', '机动车驾驶人初次申领驾驶证后的实习期是多长时间？', '{"A":"6个月","B":"12个月","C":"18个月","D":"24个月"}', 'B', '机动车驾驶人初次申领机动车驾驶证后的12个月为实习期。', 1, '道路交通安全法律法规'),
(1, 'single', '道路交通安全违法行为累积记分周期为多长时间？', '{"A":"6个月","B":"12个月","C":"18个月","D":"24个月"}', 'B', '道路交通安全违法行为累积记分周期为12个月，从机动车驾驶证初次领取之日起计算。', 1, '道路交通安全法律法规'),
(1, 'single', '驾驶机动车发生交通事故后当事人故意破坏、伪造现场、毁灭证据的，应当承担什么责任？', '{"A":"主要责任","B":"次要责任","C":"同等责任","D":"全部责任"}', 'D', '当事人故意破坏、伪造现场、毁灭证据的，承担全部责任。', 3, '道路交通安全法律法规'),
(1, 'judge', '驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，能见度在50米以下时，应开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路。', '{"A":"正确","B":"错误"}', 'A', '根据《道路交通安全法实施条例》规定，能见度小于50米时，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路。', 3, '道路交通安全法律法规'),
(1, 'single', '机动车驾驶人在一个记分周期内累积记分达到12分的，公安机关交通管理部门应当扣留其机动车驾驶证，该机动车驾驶人应当按照规定参加道路交通安全法律、法规的学习并接受考试。考试合格的，记分予以清除，发还机动车驾驶证；考试不合格的，继续参加学习和考试。', '{"A":"正确","B":"错误"}', 'A', '依据《道路交通安全法实施条例》规定，机动车驾驶人在一个记分周期内累积记分达到12分的，应当参加学习并接受考试。', 2, '道路交通安全法律法规'),

(1, 'single', '交通信号灯由红灯、绿灯和黄灯组成，红灯表示什么？', '{"A":"禁止通行","B":"准许通行","C":"警示","D":"停止通行"}', 'D', '红灯表示禁止通行，但右转弯的车辆在不妨碍被放行的车辆、行人通行的情况下，可以通行。', 1, '道路交通信号'),
(1, 'single', '交通信号灯黄灯闪烁时，车辆、行人应怎样通行？', '{"A":"不准通行","B":"在确保安全的原则下通行","C":"加速通行","D":"停车等待"}', 'B', '黄灯闪烁时，车辆、行人须在确保安全的原则下通行。', 2, '道路交通信号'),
(1, 'single', '红色叉形灯或者箭头灯亮时，表示什么？', '{"A":"本车道禁止车辆通行","B":"其他车道禁止车辆通行","C":"本车道准许车辆通行","D":"所有车道禁止车辆通行"}', 'A', '红色叉形灯或者箭头灯亮时，本车道禁止车辆通行。', 1, '道路交通信号'),
(1, 'single', '驾驶机动车在没有道路中心线的道路上行驶，应当在道路的哪侧通行？', '{"A":"左侧","B":"右侧","C":"中间","D":"任意一侧"}', 'B', '在没有划分机动车道、非机动车道和人行道的道路上，机动车在道路中间通行，但应当靠右侧行驶。', 1, '道路交通信号'),
(1, 'judge', '机动车在高速公路上行驶，车速超过每小时100公里时，与同车道前车的最小距离不得少于50米。', '{"A":"正确","B":"错误"}', 'B', '机动车在高速公路上行驶，车速超过每小时100公里时，与同车道前车的最小距离不得少于100米。', 2, '道路交通信号'),

(1, 'single', '机动车在紧急制动时ABS系统会起到什么作用？', '{"A":"切断动力输出","B":"防止车轮抱死","C":"减轻车辆惯性","D":"自动控制方向"}', 'B', 'ABS系统即防抱死制动系统，其作用是防止车轮抱死，使车辆在制动时仍能转向。', 2, '安全行车、文明驾驶'),
(1, 'single', '在暴雨天气驾车，刮水器无法刮净雨水时，应怎样做？', '{"A":"减速行驶","B":"集中注意力谨慎驾驶","C":"立即减速靠边停驶","D":"以正常速度行驶"}', 'C', '暴雨天气刮水器无法刮净雨水时，驾驶人视线严重受阻，应立即减速靠边停驶，开启危险报警闪光灯。', 3, '安全行车、文明驾驶'),
(1, 'single', '车辆发生碰撞时，关于安全带作用的说法错误的是什么？', '{"A":"保护颈部不受伤害","B":"减轻驾乘人员受伤程度","C":"减轻驾驶人疲劳","D":"保持正确驾驶姿势"}', 'C', '安全带的作用是当汽车紧急制动或发生碰撞时，减轻驾乘人员的受伤程度，保护驾乘人员的安全。', 2, '安全行车、文明驾驶'),
(1, 'single', '发生交通事故后，防止二次事故的有效措施是什么？', '{"A":"放置警告标志","B":"开启危险报警闪光灯","C":"人员转移到安全地点","D":"以上都是"}', 'D', '发生交通事故后，应立即开启危险报警闪光灯，在车后放置警告标志，人员转移到安全地点，防止二次事故。', 2, '安全行车、文明驾驶'),
(1, 'judge', '在大雨天行车，为避免发生水滑而造成危险，要控制速度行驶。', '{"A":"正确","B":"错误"}', 'A', '雨天行车，路面湿滑，应控制车速，避免发生水滑现象。', 1, '安全行车、文明驾驶'),

(1, 'single', '机动车在道路上变更车道需要注意什么？', '{"A":"提前开启转向灯","B":"加速行驶","C":"随意变更","D":"紧急制动"}', 'A', '变更车道时，应提前开启转向灯，确认安全后驶入需要变更的车道。', 1, '机动车驾驶操作相关基础知识'),
(1, 'single', '机动车在道路上发生故障，需要停车排除时，驾驶人应当立即开启什么灯？', '{"A":"左转向灯","B":"右转向灯","C":"危险报警闪光灯","D":"前照灯"}', 'C', '机动车在道路上发生故障，需要停车排除时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放。', 2, '机动车驾驶操作相关基础知识'),
(1, 'single', '机动车在夜间行驶，路灯照明良好时，应当使用什么灯光？', '{"A":"远光灯","B":"近光灯","C":"危险报警闪光灯","D":"示廓灯"}', 'B', '机动车在夜间行驶，路灯照明良好时，应当使用近光灯。', 1, '机动车驾驶操作相关基础知识'),
(1, 'single', '驾驶机动车下长坡时，空挡滑行会导致什么后果？', '{"A":"油耗增加","B":"制动器制动效果下降","C":"发动机熄火","D":"转向失灵"}', 'B', '空挡滑行时，发动机与驱动轮断开连接，无法利用发动机制动，长时间使用行车制动器会导致制动器制动效果下降。', 3, '机动车驾驶操作相关基础知识'),
(1, 'judge', '驾驶机动车下长坡时，仅靠行车制动器制动是不够的，应利用发动机的牵阻作用控制车速。', '{"A":"正确","B":"错误"}', 'A', '下长坡时，应利用发动机的牵阻作用控制车速，避免长时间使用行车制动器导致制动效果下降。', 2, '机动车驾驶操作相关基础知识'),

(1, 'single', '在冰雪路面行驶时，应当怎样操作？', '{"A":"高速行驶","B":"低速行驶","C":"紧急制动","D":"急打方向"}', 'B', '冰雪路面行驶时，应低速行驶，保持安全距离，避免紧急制动和急打方向。', 2, '恶劣气象和复杂道路条件下的驾驶常识'),
(1, 'single', '在泥泞路段行车，应怎样控制速度？', '{"A":"高速通过","B":"低速平稳通过","C":"加速通过","D":"匀速通过"}', 'B', '泥泞路段应低速平稳通过，避免车轮打滑。', 2, '恶劣气象和复杂道路条件下的驾驶常识'),
(1, 'single', '雾天行车，应怎样使用灯光？', '{"A":"使用远光灯","B":"使用近光灯","C":"使用雾灯和危险报警闪光灯","D":"不使用灯光"}', 'C', '雾天行车，应开启雾灯和危险报警闪光灯，减速慢行。', 2, '恶劣气象和复杂道路条件下的驾驶常识'),
(1, 'judge', '在大风天气行车，应适当降低车速，握稳方向盘，防止行驶路线偏移。', '{"A":"正确","B":"错误"}', 'A', '大风天气行车，应降低车速，握稳方向盘，防止风力影响行驶方向。', 1, '恶劣气象和复杂道路条件下的驾驶常识'),

(1, 'single', '行车中遇有前方发生交通事故，需要帮助时，应怎样做？', '{"A":"绕道躲避","B":"立即报警，停车观望","C":"协助保护现场，并立即报警","D":"加速通过，不予理睬"}', 'C', '行车中遇有前方发生交通事故，应协助保护现场，并立即报警。', 2, '紧急情况避险'),
(1, 'single', '行车中遇抢救伤员的救护车从本车道逆向驶来时，应怎样做？', '{"A":"靠边减速或停车让行","B":"占用其他车道行驶","C":"加速变更车道避让","D":"在原车道内继续行驶"}', 'A', '遇救护车执行紧急任务时，应靠边减速或停车让行。', 2, '紧急情况避险'),
(1, 'single', '行车中发动机突然熄火后，应怎样做？', '{"A":"立即停车检修","B":"立即开启危险报警闪光灯","C":"将机动车停到不妨碍交通的地点","D":"放置警告标志"}', 'C', '发动机突然熄火后，应将机动车停到不妨碍交通的地点，开启危险报警闪光灯，放置警告标志。', 2, '紧急情况避险'),
(1, 'judge', '车辆在高速公路上发生故障，依法采取必要的安全措施后，车上人员应当在车内等待救援。', '{"A":"正确","B":"错误"}', 'B', '车辆在高速公路上发生故障，车上人员应当迅速转移到右侧路肩上或者应急车道内，并迅速报警。', 3, '紧急情况避险'),

(1, 'single', '机动车在高速公路上发生故障时，警告标志应当设置在故障车来车方向多少米外？', '{"A":"50米","B":"100米","C":"150米","D":"200米"}', 'C', '机动车在高速公路上发生故障时，警告标志应当设置在故障车来车方向150米外。', 2, '交通事故处置'),
(1, 'single', '在道路上发生交通事故，造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。', '{"A":"正确","B":"错误"}', 'A', '根据《道路交通安全法》规定，在道路上发生交通事故，造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。', 2, '交通事故处置'),
(1, 'single', '发生交通事故后，当事人故意破坏、伪造现场、毁灭证据的，承担什么责任？', '{"A":"主要责任","B":"次要责任","C":"同等责任","D":"全部责任"}', 'D', '当事人故意破坏、伪造现场、毁灭证据的，承担全部责任。', 2, '交通事故处置'),
(1, 'judge', '在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜。', '{"A":"正确","B":"错误"}', 'A', '根据《道路交通安全法》规定，在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜。', 1, '交通事故处置');
